func nextGreater(nums []int) []int {
    res := make([]int, len(nums))
    for i := range res { res[i] = -1 }
    stack := []int{} // indices
    for i, n := range nums {
        for len(stack) > 0 && nums[stack[len(stack)-1]] < n {
            idx := stack[len(stack)-1]
            stack = stack[:len(stack)-1]
            res[idx] = n
        }
        stack = append(stack, i)
    }
    return res
}

