import java.util.Deque;
import java.util.ArrayDeque;

// Java: use Deque (ArrayDeque) — Stack class is legacy
Deque<Integer> stack = new ArrayDeque<>();

stack.push(1);   // push to front
stack.push(2);
stack.push(3);

int top = stack.peek();  // peek — top element, no removal → 3
int val = stack.pop();   // pop  — removes and returns top  → 3

boolean empty = stack.isEmpty();
int size = stack.size();

// Monotonic stack
int[] nextGreater(int[] nums) {
    int n = nums.length;
    int[] res = new int[n];
    Arrays.fill(res, -1);
    Deque<Integer> st = new ArrayDeque<>(); // indices
    for (int i = 0; i < n; i++) {
        while (!st.isEmpty() && nums[st.peek()] < nums[i])
            res[st.pop()] = nums[i];
        st.push(i);
    }
    return res;
}

