import java.util.Deque;
import java.util.ArrayDeque;
import java.util.PriorityQueue;

// Queue using Deque
Deque<Integer> queue = new ArrayDeque<>();

queue.offer(1);  // enqueue (add to back)
queue.offer(2);
queue.offer(3);

