func inorderIter(root *TreeNode) []int {
    var res []int
    var stack []*TreeNode
    cur := root
    for cur != nil || len(stack) > 0 {
        for cur != nil { stack = append(stack, cur); cur = cur.Left }
        cur = stack[len(stack)-1]; stack = stack[:len(stack)-1]
        res = append(res, cur.Val)
        cur = cur.Right
    }
