// Iterative preorder
func preorderIter(root *TreeNode) []int {
    if root == nil { return nil }
    var res []int
    stack := []*TreeNode{root}
    for len(stack) > 0 {
        n := stack[len(stack)-1]; stack = stack[:len(stack)-1]
        res = append(res, n.Val)
        if n.Right != nil { stack = append(stack, n.Right) }
        if n.Left  != nil { stack = append(stack, n.Left)  }
    }
