func (st *SegTree) build(nums []int, node, start, end int) {
    if start==end { st.Tree[node]=nums[start]; return }
    mid:=(start+end)/2
    st.build(nums, 2*node+1, start, mid)
    st.build(nums, 2*node+2, mid+1, end)
    st.Tree[node]=st.Tree[2*node+1]+st.Tree[2*node+2]
}
func (st *SegTree) Update(idx, val int) { st.update(idx,val,0,0,st.N-1) }
func (st *SegTree) update(idx,val,node,start,end int) {
    if start==end { st.Tree[node]=val; return }
    mid:=(start+end)/2
    if idx<=mid { st.update(idx,val,2*node+1,start,mid) }
    else        { st.update(idx,val,2*node+2,mid+1,end) }
    st.Tree[node]=st.Tree[2*node+1]+st.Tree[2*node+2]
}
func (st *SegTree) Query(l,r int) int { return st.query(l,r,0,0,st.N-1) }
func (st *SegTree) query(l,r,node,start,end int) int {
    if r<start || end<l { return 0 }
    if l<=start && end<=r { return st.Tree[node] }
    mid:=(start+end)/2
    return st.query(l,r,2*node+1,start,mid)+
           st.query(l,r,2*node+2,mid+1,end)
}

