from collections import defaultdict, deque

# Kahn's Algorithm (BFS)
def topo_sort_kahn(n, edges):
    adj = defaultdict(list)
    indegree = [0] * n
    for u, v in edges:
        adj[u].append(v)
        indegree[v] += 1
    queue = deque(i for i in range(n) if indegree[i] == 0)
    order = []
    while queue:
        node = queue.popleft()
        order.append(node)
        for nei in adj[node]:
            indegree[nei] -= 1
            if indegree[nei] == 0:
                queue.append(nei)
    return order if len(order) == n else []  # empty = cycle

# DFS Post-order
def topo_sort_dfs(n, edges):
    adj = defaultdict(list)
    for u, v in edges:
        adj[u].append(v)
    visited = [False] * n
    result = []
    def dfs(node):
        visited[node] = True
        for nei in adj[node]:
            if not visited[nei]:
                dfs(nei)
        result.append(node)
    for i in range(n):
        if not visited[i]:
            dfs(i)
    return result[::-1]

