// Kahn's Algorithm
func topoKahn(n int, edges [][2]int) []int {
    adj := make([][]int, n)
    indegree := make([]int, n)
    for _, e := range edges {
        adj[e[0]] = append(adj[e[0]], e[1])
        indegree[e[1]]++
    }
    queue := []int{}
    for i := 0; i < n; i++ {
        if indegree[i] == 0 { queue = append(queue, i) }
    }
    order := []int{}
    for len(queue) > 0 {
        node := queue[0]; queue = queue[1:]
        order = append(order, node)
        for _, nei := range adj[node] {
            indegree[nei]--
            if indegree[nei] == 0 { queue = append(queue, nei) }
        }
    }
    if len(order) == n { return order }
    return nil // cycle detected
}

// DFS Post-order
func topoDFS(n int, edges [][2]int) []int {
    adj := make([][]int, n)
    for _, e := range edges { adj[e[0]] = append(adj[e[0]], e[1]) }
    visited := make([]bool, n)
    result := []int{}
    var dfs func(int)
    dfs = func(node int) {
        visited[node] = true
        for _, nei := range adj[node] {
            if !visited[nei] { dfs(nei) }
        }
        result = append(result, node)
    }
    for i := 0; i < n; i++ {
        if !visited[i] { dfs(i) }
    }
    // reverse result
    for i, j := 0, len(result)-1; i < j; i, j = i+1, j-1 {
        result[i], result[j] = result[j], result[i]
    }
    return result
}

