import java.util.*;

// Kahn's Algorithm
static int[] topoKahn(int n, int[][] edges) {
    List<List<Integer>> adj = new ArrayList<>();
    int[] indegree = new int[n];
    for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
    for (int[] e : edges) { adj.get(e[0]).add(e[1]); indegree[e[1]]++; }
    Queue<Integer> q = new LinkedList<>();
    for (int i = 0; i < n; i++) if (indegree[i] == 0) q.offer(i);
    int[] order = new int[n]; int idx = 0;
    while (!q.isEmpty()) {
        int node = q.poll();
        order[idx++] = node;
        for (int nei : adj.get(node))
            if (--indegree[nei] == 0) q.offer(nei);
    }
    return idx == n ? order : new int[0]; // empty = cycle
}

// DFS Post-order
static List<Integer> topoDFS(int n, int[][] edges) {
    List<List<Integer>> adj = new ArrayList<>();
    for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
    for (int[] e : edges) adj.get(e[0]).add(e[1]);
    boolean[] visited = new boolean[n];
    LinkedList<Integer> result = new LinkedList<>();
    for (int i = 0; i < n; i++)
        if (!visited[i]) dfs(i, adj, visited, result);
    return result;
}
static void dfs(int u, List<List<Integer>> adj, boolean[] vis, LinkedList<Integer> res) {
    vis[u] = true;
    for (int v : adj.get(u)) if (!vis[v]) dfs(v, adj, vis, res);
    res.addFirst(u); // prepend = reverse post-order
}

