    visited = [False] * n
    def dfs(node, parent):
        visited[node] = True
        for nei in adj[node]:
            if not visited[nei]:
                if dfs(nei, node): return True
            elif nei != parent:  # visited and not parent
                return True
        return False
    return any(dfs(i, -1) for i in range(n) if not visited[i])

