import "container/heap"

type Item struct{ node, dist int }
type PQ []Item
func (p PQ) Len() int            { return len(p) }
func (p PQ) Less(i, j int) bool  { return p[i].dist < p[j].dist }
func (p PQ) Swap(i, j int)       { p[i], p[j] = p[j], p[i] }
func (p *PQ) Push(x interface{}) { *p = append(*p, x.(Item)) }
func (p *PQ) Pop() interface{}   { old:=*p; n:=len(old); x:=old[n-1]; *p=old[:n-1]; return x }

func dijkstra(n int, edges [][3]int, src int) []int {
    adj := make([][][2]int, n)
    for _, e := range edges {
        adj[e[0]] = append(adj[e[0]], [2]int{e[1], e[2]})
        adj[e[1]] = append(adj[e[1]], [2]int{e[0], e[2]})
    }
    const INF = 1<<62
    dist := make([]int, n)
    for i := range dist { dist[i] = INF }
    dist[src] = 0
    pq := &PQ{{src, 0}}
    heap.Init(pq)
    for pq.Len() > 0 {
        cur := heap.Pop(pq).(Item)
        if cur.dist > dist[cur.node] { continue }
        for _, e := range adj[cur.node] {
            if nd := dist[cur.node] + e[1]; nd < dist[e[0]] {
                dist[e[0]] = nd
                heap.Push(pq, Item{e[0], nd})
            }
        }
    }
    return dist
}

