// Kruskal's
func kruskal(n int, edges [][3]int) int {
    sort.Slice(edges, func(i,j int) bool { return edges[i][2] < edges[j][2] })
    parent := make([]int, n)
    rank := make([]int, n)
    for i := range parent { parent[i] = i }
    var find func(int) int
    find = func(x int) int {
        if parent[x] != x { parent[x] = find(parent[x]) }
        return parent[x]
    }
    union := func(a, b int) bool {
        a, b = find(a), find(b)
        if a == b { return false }
        if rank[a] < rank[b] { a, b = b, a }
        parent[b] = a
        if rank[a] == rank[b] { rank[a]++ }
        return true
    }
    total := 0
    for _, e := range edges {
        if union(e[0], e[1]) { total += e[2] }
    }
    return total
}

// Prim's (reuses Dijkstra-style PQ)
func prim(n int, edges [][3]int) int {
    adj := make([][][2]int, n)
    for _, e := range edges {
        adj[e[0]] = append(adj[e[0]], [2]int{e[1], e[2]})
        adj[e[1]] = append(adj[e[1]], [2]int{e[0], e[2]})
    }
    visited := make([]bool, n)
    pq := &PQ{{0, 0}} // reuse PQ from Dijkstra card
    heap.Init(pq)
    total := 0
    for pq.Len() > 0 {
        cur := heap.Pop(pq).(Item)
        if visited[cur.node] { continue }
        visited[cur.node] = true; total += cur.dist
        for _, e := range adj[cur.node] {
            if !visited[e[0]] { heap.Push(pq, Item{e[0], e[1]}) }
        }
    }
    return total
}

