import java.util.*;

// Kruskal's
static int kruskal(int n, int[][] edges) {
    Arrays.sort(edges, Comparator.comparingInt(e -> e[2]));
    int[] parent = new int[n], rank = new int[n];
    for (int i = 0; i < n; i++) parent[i] = i;
    int total = 0;
    for (int[] e : edges) {
        int pu = find(parent, e[0]), pv = find(parent, e[1]);
        if (pu == pv) continue;
        if (rank[pu] < rank[pv]) { int t=pu; pu=pv; pv=t; }
        parent[pv] = pu;
        if (rank[pu] == rank[pv]) rank[pu]++;
        total += e[2];
    }
    return total;
}
static int find(int[] parent, int x) {
    if (parent[x] != x) parent[x] = find(parent, parent[x]);
    return parent[x];
}

// Prim's
static int prim(int n, int[][] edges) {
    List<int[]>[] adj = new List[n];
    for (int i=0;i<n;i++) adj[i] = new ArrayList<>();
    for (int[] e : edges) {
        adj[e[0]].add(new int[]{e[1],e[2]});
        adj[e[1]].add(new int[]{e[0],e[2]});
    }
    boolean[] visited = new boolean[n];
    PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a->a[0]));
    pq.offer(new int[]{0,0}); // [weight, node]
    int total = 0;
    while (!pq.isEmpty()) {
        int[] cur = pq.poll();
        if (visited[cur[1]]) continue;
        visited[cur[1]] = true; total += cur[0];
        for (int[] e : adj[cur[1]])
            if (!visited[e[0]]) pq.offer(new int[]{e[1],e[0]});
    }
    return total;
}

