class DSU {
    int[] parent, rank;
    int components;

    DSU(int n) {
        parent = new int[n];
        rank = new int[n];
        components = n;
        for (int i = 0; i < n; i++) parent[i] = i;
    }

    int find(int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]]; // path halving
            x = parent[x];
        }
        return x;
    }

    boolean union(int a, int b) {
        a = find(a); b = find(b);
        if (a == b) return false;
        if (rank[a] < rank[b]) { int t=a; a=b; b=t; }
        parent[b] = a;
        if (rank[a] == rank[b]) rank[a]++;
        components--;
        return true;
    }

    boolean connected(int a, int b) {
        return find(a) == find(b);
    }
}

// Usage
